import {
  scaleLinear,
  type ScaleLinear,
  scaleLog,
  type ScaleLogarithmic,
} from 'd3-scale';

import type { Location } from '../../../types/location.js';

const calculateDomain = <T extends Location>(
  data: T[],
  radius: (item: T) => number,
): [number, number] => {
  let domain: [number, number] = [Infinity, -Infinity];

  for (let i = 0; i < data.length; i++) {
    const radiusValue = radius(data[i]);

    const [currentMin, currentMax] = domain;

    domain = [
      Math.min(currentMin, radiusValue),
      Math.max(currentMax, radiusValue),
    ];
  }

  return domain;
};

export const buildRadiusScale = <T extends Location>(
  data: T[],
  radius: (item: T) => number,
  scale: 'linear' | 'log',
  range: [number, number],
): ScaleLinear<number, number> | ScaleLogarithmic<number, number> => {
  const [minRadius, maxRadius] = range;
  const domain = calculateDomain(data, radius);

  if (scale === 'linear') {
    return scaleLinear(domain, [minRadius, maxRadius]);
  }

  return scaleLog(domain, [minRadius, maxRadius]);
};
